enum IntegrityRisk: String {
    case jailbroken = "Device is jailbroken"
    case debuggerDetected = "Debugger detected"
    case invalidSignature = "Invalid code signature"
    case suspiciousFiles = "Suspicious files detected"
    case simulator = "Running on simulator"
    case hookingDetected = "Hooking framework detected"
}

struct DeviceIntegrityStatus {
    let risks: [IntegrityRisk]
    
    var isCompromised: Bool {
        return !risks.isEmpty
    }
    
    var isCritical: Bool {
        return risks.contains { risk in
            risk == .jailbroken || risk == .hookingDetected || risk == .debuggerDetected
        }
    }
    
    var riskLevel: RiskLevel {
        if risks.isEmpty {
            return .none
        } else if isCritical {
            return .critical
        } else {
            return .moderate
        }
    }
}

enum RiskLevel {
    case none
    case moderate
    case critical
}

