// MARK: - Encryption Manager
class EncryptionManager {
    static let shared = EncryptionManager()
    
    private init() {}
    
    func encrypt(data: Data, key: Data) -> Data? {
        return crypt(data: data, key: key, operation: CCOperation(kCCEncrypt))
    }
    
    func decrypt(data: Data, key: Data) -> Data? {
        return crypt(data: data, key: key, operation: CCOperation(kCCDecrypt))
    }
    
    private func crypt(data: Data, key: Data, operation: CCOperation) -> Data? {
        let keyLength = kCCKeySizeAES256
        let ivSize = kCCBlockSizeAES128
        
        var iv = Data(count: ivSize)
        _ = iv.withUnsafeMutableBytes { ivBytes in
            SecRandomCopyBytes(kSecRandomDefault, ivSize, ivBytes.baseAddress!)
        }
        
        let dataLength = data.count
        let cryptLength = dataLength + kCCBlockSizeAES128
        var cryptData = Data(count: cryptLength)
        
        var numBytesEncrypted: size_t = 0
        
        let cryptStatus = cryptData.withUnsafeMutableBytes { cryptBytes in
            data.withUnsafeBytes { dataBytes in
                iv.withUnsafeBytes { ivBytes in
                    key.withUnsafeBytes { keyBytes in
                        CCCrypt(
                            operation,
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress, keyLength,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress, dataLength,
                            cryptBytes.baseAddress, cryptLength,
                            &numBytesEncrypted
                        )
                    }
                }
            }
        }
        
        if cryptStatus == kCCSuccess {
            cryptData.count = numBytesEncrypted
            if operation == kCCEncrypt {
                return iv + cryptData
            } else {
                return cryptData
            }
        }
        
        return nil
    }
    
    func generateKey() -> Data {
        var keyData = Data(count: kCCKeySizeAES256)
        _ = keyData.withUnsafeMutableBytes { keyBytes in
            SecRandomCopyBytes(kSecRandomDefault, kCCKeySizeAES256, keyBytes.baseAddress!)
        }
        return keyData
    }
}

