// MARK: - API Manager
class APIManager {
    static let shared = APIManager()
    
    private let baseURL = "https://api.tradingplatform.com/v1"
    private var authToken: String?
    
    private init() {
        loadAuthToken()
    }
    
    private func loadAuthToken() {
        authToken = SecureStorageManager.shared.retrieve(key: "authToken")
    }
    
    func setAuthToken(_ token: String) {
        authToken = token
        _ = SecureStorageManager.shared.save(key: "authToken", value: token)
    }
    
    func clearAuthToken() {
        authToken = nil
        _ = SecureStorageManager.shared.delete(key: "authToken")
    }
    
    private func createRequest(endpoint: String, method: String, body: Data? = nil) -> URLRequest? {
        guard let url = URL(string: "\(baseURL)\(endpoint)") else { return nil }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = body
        }
        
        return request
    }
    
    func login(username: String, password: String, completion: @escaping (Result<User, Error>) -> Void) {
        let integrityStatus = DeviceIntegrityManager.shared.performIntegrityChecks()
        
