        label.font = .systemFont(ofSize: 24, weight: .bold)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let cashBalanceLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 16)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadPortfolio()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Portfolio"
        
        view.addSubview(totalValueLabel)
        view.addSubview(cashBalanceLabel)
        view.addSubview(tableView)
        
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(HoldingCell.self, forCellReuseIdentifier: "HoldingCell")
        
        NSLayoutConstraint.activate([
            totalValueLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 20),
            totalValueLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            totalValueLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            cashBalanceLabel.topAnchor.constraint(equalTo: totalValueLabel.bottomAnchor, constant: 10),
            cashBalanceLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            cashBalanceLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            tableView.topAnchor.constraint(equalTo: cashBalanceLabel.bottomAnchor, constant: 20),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .refresh, target: self, action: #selector(loadPortfolio))
    }
    
    @objc private func loadPortfolio() {
        APIManager.shared.getPortfolio { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let portfolio):
                    self?.portfolio = portfolio
                    self?.updateUI()
                    
                case .failure(let error):
                    self?.showAlert(message: error.localizedDescription)
                }
            }
        }
    }
    
    private func updateUI() {
        guard let portfolio = portfolio else { return }
        
        totalValueLabel.text = String(format: "$%.2f", portfolio.totalValue)
        cashBalanceLabel.text = String(format: "Cash: $%.2f", portfolio.cashBalance)
        tableView.reloadData()
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return portfolio?.holdings.count ?? 0
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "HoldingCell", for: indexPath) as! HoldingCell
        
        if let holding = portfolio?.holdings[indexPath.row] {
            cell.configure(with: holding)
        }
        
        return cell
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

