class TradeViewController: UIViewController {
    
    private let symbolTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "Stock Symbol (e.g., AAPL)"
        textField.borderStyle = .roundedRect
        textField.autocapitalizationType = .allCharacters
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let quantityTextField: UITextField = {
        let textField = UITextField()
        textField.placeholder = "Quantity"
        textField.borderStyle = .roundedRect
        textField.keyboardType = .numberPad
        textField.translatesAutoresizingMaskIntoConstraints = false
        return textField
    }()
    
    private let tradeTypeSegment: UISegmentedControl = {
        let segment = UISegmentedControl(items: ["Buy", "Sell"])
        segment.selectedSegmentIndex = 0
        segment.translatesAutoresizingMaskIntoConstraints = false
        return segment
    }()
    
    private let currentPriceLabel: UILabel = {
        let label = UILabel()
        label.text = "Current Price: --"
        label.font = .systemFont(ofSize: 18)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let executeButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Execute Trade", for: .normal)
        button.backgroundColor = .systemGreen
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 8
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let getQuoteButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Get Quote", for: .normal)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private var currentStock: Stock?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        checkDeviceIntegrity()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Trade"
        
        view.addSubview(symbolTextField)
        view.addSubview(getQuoteButton)
        view.addSubview(currentPriceLabel)
        view.addSubview(quantityTextField)
        view.addSubview(tradeTypeSegment)
        view.addSubview(executeButton)
        
        NSLayoutConstraint.activate([
            symbolTextField.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 30),
            symbolTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            symbolTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            symbolTextField.heightAnchor.constraint(equalToConstant: 44),
            
            getQuoteButton.topAnchor.constraint(equalTo: symbolTextField.bottomAnchor, constant: 10),
            getQuoteButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            currentPriceLabel.topAnchor.constraint(equalTo: getQuoteButton.bottomAnchor, constant: 20),
            currentPriceLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            currentPriceLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            quantityTextField.topAnchor.constraint(equalTo: currentPriceLabel.bottomAnchor, constant: 30),
            quantityTextField.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            quantityTextField.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            quantityTextField.heightAnchor.constraint(equalToConstant: 44),
            
            tradeTypeSegment.topAnchor.constraint(equalTo: quantityTextField.bottomAnchor, constant: 20),
            tradeTypeSegment.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            tradeTypeSegment.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            
            executeButton.topAnchor.constraint(equalTo: tradeTypeSegment.bottomAnchor, constant: 40),
            executeButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            executeButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20),
            executeButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        getQuoteButton.addTarget(self, action: #selector(getQuoteTapped), for: .touchUpInside)
        executeButton.addTarget(self, action: #selector(executeTradeTapped), for: .touchUpInside)
    }
    
    private func checkDeviceIntegrity() {
        let integrityStatus = DeviceIntegrityManager.shared.performIntegrityChecks()
        
        if integrityStatus.isCritical {
            executeButton.isEnabled = false
            executeButton.backgroundColor = .systemGray
            showAlert(message: "Trading is disabled due to device security concerns.")
        }
    }
    
    @objc private func getQuoteTapped() {
        guard let symbol = symbolTextField.text?.uppercased(), !symbol.isEmpty else {
            showAlert(message: "Please enter a stock symbol")
            return
        }
        
        APIManager.shared.getStockQuote(symbol: symbol) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let stock):
                    self?.currentStock = stock
                    self?.currentPriceLabel.text = String(format: "Current Price: $%.2f", stock.currentPrice)
                    
                case .failure(let error):
                    self?.showAlert(message: error.localizedDescription)
                }
            }
        }
    }
    
    @objc private func executeTradeTapped() {
        guard let symbol = symbolTextField.text?.uppercased(), !symbol.isEmpty else {
            showAlert(message: "Please enter a stock symbol")
            return
        }
        
        guard let quantityText = quantityTextField.text, let quantity = Int(quantityText), quantity > 0 else {
            showAlert(message: "Please enter a valid quantity")
            return
        }
        
        let tradeType: TradeType = tradeTypeSegment.selectedSegmentIndex == 0 ? .buy : .sell
        
        executeButton.isEnabled = false
        
        APIManager.shared.executeTrade(symbol: symbol, type: tradeType, quantity: quantity) { [weak self] result in
            DispatchQueue.main.async {
                self?.executeButton.isEnabled = true
                
                switch result {
                case .success(let trade):
                    self?.showSuccessAlert(trade: trade)
                    self?.clearForm()
                    
                case .failure(let error):
                    self?.showAlert(message: error.localizedDescription)
                }
            }
        }
    }
    
    private func clearForm() {
        symbolTextField.text = ""
        quantityTextField.text = ""
        currentPriceLabel.text = "Current Price: --"
        currentStock = nil
        tradeTypeSegment.selectedSegmentIndex = 0
    }
    
    private func showSuccessAlert(trade: Trade) {
        let message = "Trade executed successfully!\n\(trade.type.rawValue.capitalized) \(trade.quantity) shares of \(trade.symbol) at $\(String(format: "%.2f", trade.price))"
        let alert = UIAlertController(title: "Success", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

class TradeHistoryViewController: UIViewController, UITableViewDelegate, UITableViewDataSource {
    
    private var trades: [Trade] = []
    
    private let tableView: UITableView = {
        let table = UITableView()
        table.translatesAutoresizingMaskIntoConstraints = false
        return table
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        loadTradeHistory()
    }
    
    override func viewWillAppear(_ animated: Bool) {
        super.viewWillAppear(animated)
        loadTradeHistory()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Trade History"
        
        view.addSubview(tableView)
        
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(TradeCell.self, forCellReuseIdentifier: "TradeCell")
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(barButtonSystemItem: .refresh, target: self, action: #selector(loadTradeHistory))
    }
    
    @objc private func loadTradeHistory() {
        APIManager.shared.getTradeHistory { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let trades):
                    self?.trades = trades.sorted { $0.timestamp > $1.timestamp }
                    self?.tableView.reloadData()
                    
                case .failure(let error):
                    self?.showAlert(message: error.localizedDescription)
                }
            }
        }
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return trades.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TradeCell", for: indexPath) as! TradeCell
        cell.configure(with: trades[indexPath.row])
        return cell
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

