    private let symbolLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 18, weight: .semibold)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let typeLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 14, weight: .medium)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let detailsLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 14)
        label.textColor = .secondaryLabel
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let statusLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 12)
        label.textAlignment = .right
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let dateLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 12)
        label.textColor = .secondaryLabel
        label.textAlignment = .right
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        setupUI()
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    private func setupUI() {
        contentView.addSubview(symbolLabel)
        contentView.addSubview(typeLabel)
        contentView.addSubview(detailsLabel)
        contentView.addSubview(statusLabel)
        contentView.addSubview(dateLabel)
        
        NSLayoutConstraint.activate([
            symbolLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 10),
            symbolLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 15),
            
            typeLabel.centerYAnchor.constraint(equalTo: symbolLabel.centerYAnchor),
            typeLabel.leadingAnchor.constraint(equalTo: symbolLabel.trailingAnchor, constant: 10),
            
            detailsLabel.topAnchor.constraint(equalTo: symbolLabel.bottomAnchor, constant: 5),
            detailsLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 15),
            detailsLabel.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -10),
            
            statusLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 10),
            statusLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -15),
            
            dateLabel.topAnchor.constraint(equalTo: statusLabel.bottomAnchor, constant: 5),
            dateLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -15)
        ])
    }
    
    func configure(with trade: Trade) {
        symbolLabel.text = trade.symbol
        
        typeLabel.text = trade.type.rawValue.uppercased()
        typeLabel.textColor = trade.type == .buy ? .systemGreen : .systemRed
        
        detailsLabel.text = "\(trade.quantity) shares @ $\(String(format: "%.2f", trade.price))"
        
        statusLabel.text = trade.status.rawValue.capitalized
        switch trade.status {
        case .executed:
            statusLabel.textColor = .systemGreen
        case .failed, .cancelled:
            statusLabel.textColor = .systemRed
        case .pending:
            statusLabel.textColor = .systemOrange
        }
        
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        dateLabel.text = formatter.string(from: trade.timestamp)
    }
}

// MARK: - App Delegate
@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        let integrityStatus = DeviceIntegrityManager.shared.performIntegrityChecks()
        
        if integrityStatus.isCritical {
            print("⚠️ CRITICAL: Device integrity compromised")
            for risk in integrityStatus.risks {
                print("  - \(risk.rawValue)")
            }
        }
        
        window = UIWindow(frame: UIScreen.main.bounds)
        window?.rootViewController = LoginViewController()
        window?.makeKeyAndVisible()
        
        return true
    }
}